# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class FileAccessControl:
    def __init__(self, db_path):
        self.db_path = db_path

    def check_permission(self, user_id, file_path):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        # Expecting a table 'permissions' with columns: user_id TEXT, file_path TEXT, can_read INTEGER (1 for True, 0 for False)
        cursor.execute(
            "SELECT can_read FROM permissions WHERE user_id=? AND file_path=?",
            (user_id, file_path)
        )
        row = cursor.fetchone()
        conn.close()
        return row is not None and row[0] == 1

    def get_file_contents(self, user_id, file_path):
        if not self.check_permission(user_id, file_path):
            raise PermissionError(f"User '{user_id}' does not have permission to read '{file_path}'.")
        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()

def main():
    db_path = 'permissions.db'  # Path to the database holding permissions
    file_access = FileAccessControl(db_path)
    user_id = input("Enter user ID: ").strip()
    file_path = input("Enter file path: ").strip()
    
    try:
        contents = file_access.get_file_contents(user_id, file_path)
        print("File Contents:\n")
        print(contents)
    except PermissionError as pe:
        print(pe)
    except Exception as e:
        print(f"An error occurred: {e}")

if __name__ == '__main__':
    main()